@spec clipboard_spec  src=tests/specs/clipboard_spec.lua  loc=332  sha=a1b74fe  cases=8
@exercises trackerView (h.vm), editCursor (h.ec), clipboard (h.clipboard), midiManager (h.fm), trackerManager (h.tm)
@surface   vm:setGridSize, ec:setPos, ec:extendTo, ec:pos, clipboard:collect, clipboard:trimTop, fm:dump, clipboard:pasteClip, tm:deleteEvent, tm:flush, tm:addEvent, tm:getChannel
@harness   mk{seed.notes, seed.length, seed.ccs}

# Intent
  Stage-6 contract pins for the clipboard factory (newClipboard in
  viewManager.lua, scheduled to lift to clipboard.lua at 6d). These pin
  the wire format between collect and pasteClip — what shape collect
  produces, what trimTop preserves, what chanDelta means in multi mode —
  so the file move can't drift the contract silently.

# Cases
  @case 'clipboard:collect on 1×1 pitch sel produces single-mode clip with row-relative event'  [harness]  @ 17-47
  @case 'clipboard:trimTop drops top rows and re-indexes survivors'  [harness]  @ 55-75
  @case 'copy/paste carries intent ceiling, not the clipped tail'  [harness]  @ 83-113
  @case 'paste fit-clip against a blocker keeps intent; regrows when blocker removed'  [harness]  @ 120-163
  @case 'copy/paste a retrig host leaves the original host intact'  [harness]  @ 169-209
  @case 'clipboard:collect multi-col records chanDelta from leftmost col'  [harness]  @ 217-242
  @case 'arbitrary metadata survives note pitch-mode collect→paste round-trip'  [harness]  @ 253-281
  @case 'arbitrary metadata survives cc-mode collect→paste round-trip'  [harness]  @ 291-329

